solutions.cpp:
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void solve(vector<int>& arr) {
        // forward
        for (size_t i = 0; i < arr.size(); ++i) {
            if (i) cout << ' ';
            cout << arr[i];
        }
        cout << "\n";
        // backward
        for (size_t i = arr.size(); i-- > 0;) {
            if (i != arr.size() - 1) cout << ' ';
            cout << arr[i];
        }
        cout << "\n";
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; ++i) cin >> arr[i];
    Solution sol;
    sol.solve(arr);
    return 0;
}
